          // z = MaxOf(b',c') <= a' = x, so m = max(x,y,z) = x = y
          // Both x==m and y==m, so cnt >= 2, contradiction
          assert MaxOf(a', b') == a';
          assert MaxOf(a', c') == a';
          assert x == a' && y == a';
        } else if b' >= a' && b' >= c' {
          // b' is largest: MaxOf(a',b')=b'=x, MaxOf(b',c')=b'=z, so x==z
          assert MaxOf(a', b') == b';
          assert MaxOf(b', c') == b';
          assert x == b' && z == b';
        } else {
          // c' is largest: MaxOf(a',c')=c'=y, MaxOf(b',c')=c'=z, so y==z
          assert c' >= a' && c' >= b';
          assert MaxOf(a', c') == c';
          assert MaxOf(b', c') == c';
          assert y == c' && z == c';
        }
      }
    }
  }
}

